+                    .await
+            }
+            ActionKind::SendControl => client.send_control_with_cx(cx, pane_id, text).await,
+            other => Err(crate::Error::Runtime(format!(
+                "dispatch_wezterm_send_with_cx called with non-injection action: {other:?}"
+            ))),
+        }
+    }
